import{_ as a,o as i,c as n,ag as o}from"./chunks/framework.ByAj6Cie.js";const b=JSON.parse('{"title":"Contribuir","description":"","frontmatter":{},"headers":[],"relativePath":"es/home/contribute.md","filePath":"es/home/contribute.md"}'),r={name:"es/home/contribute.md"};function t(c,e,s,l,d,u){return i(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="contribuir" tabindex="-1">Contribuir <a class="header-anchor" href="#contribuir" aria-label="Permalink to &quot;Contribuir&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Este handbook es un recurso técnico curado enfocado en claridad, consistencia y comprensión práctica.</p><p>Las contribuciones son bienvenidas, pero se revisan para asegurar que el contenido mantenga una estructura consistente y un enfoque orientado a ingeniería.</p><h2 id="alcance-de-la-contribucion" tabindex="-1">Alcance de la contribución <a class="header-anchor" href="#alcance-de-la-contribucion" aria-label="Permalink to &quot;Alcance de la contribución&quot;">​</a></h2><p>Esta página está destinada a <strong>contribuciones directas al contenido</strong>, como:</p><ul><li>Edición de páginas existentes</li><li>Adición de nuevos temas</li><li>Mejora de la estructura o claridad técnica</li></ul><p>Para comentarios generales, sugerencias o correcciones, utiliza la página de feedback.</p><h2 id="como-contribuir" tabindex="-1">Cómo contribuir <a class="header-anchor" href="#como-contribuir" aria-label="Permalink to &quot;Cómo contribuir&quot;">​</a></h2><ol><li>Hacer un fork del repositorio</li><li>Crear una nueva rama</li><li>Realizar los cambios</li><li>Enviar un pull request</li></ol><h2 id="que-esperar" tabindex="-1">Qué esperar <a class="header-anchor" href="#que-esperar" aria-label="Permalink to &quot;Qué esperar&quot;">​</a></h2><p>Todas las contribuciones son revisadas antes de ser aceptadas.</p><ul><li>El contenido puede ser editado para ajustarse al estilo del handbook</li><li>Pueden aplicarse ajustes estructurales</li><li>Algunas contribuciones pueden no ser aceptadas</li></ul><p>Este proceso asegura consistencia en todos los temas.</p><h2 id="lineamientos-de-contenido" tabindex="-1">Lineamientos de contenido <a class="header-anchor" href="#lineamientos-de-contenido" aria-label="Permalink to &quot;Lineamientos de contenido&quot;">​</a></h2><p>Al contribuir, sigue estos principios:</p><ul><li>Mantener explicaciones claras y prácticas</li><li>Enfocarse en la comprensión, no en teoría excesiva</li><li>Mantener un formato estructurado y consistente</li><li>Evitar redundancia con contenido existente</li></ul><h2 id="enfoque-de-redaccion" tabindex="-1">Enfoque de redacción <a class="header-anchor" href="#enfoque-de-redaccion" aria-label="Permalink to &quot;Enfoque de redacción&quot;">​</a></h2><p>El contenido debe ayudar al lector a:</p><ul><li>Entender qué es un componente o concepto</li><li>Entender por qué se utiliza</li><li>Entender cómo aplicarlo en escenarios reales</li></ul><p>El objetivo no es reemplazar manuales, sino hacerlos más fáciles de entender y utilizar.</p><h2 id="nota-final" tabindex="-1">Nota final <a class="header-anchor" href="#nota-final" aria-label="Permalink to &quot;Nota final&quot;">​</a></h2><p>Las contribuciones bien estructuradas tienen mayor probabilidad de ser aceptadas.</p><p>Pequeñas mejoras, correcciones o aclaraciones son valiosas y ayudan a mejorar la calidad general del handbook.</p>',24)])])}const h=a(r,[["render",t]]);export{b as __pageData,h as default};
